sqlMap.insert:
INSERT INTO WeavePattern (
    Name, Code, RepeatX, RepeatY,
    Cells, WarpColors, WeftColors,
    WarpThickness, WeftThickness,
    WeaveMode, SavedAt
) VALUES (
    @name, @code, @repeatX, @repeatY,
    @cells, @warpColors, @weftColors,
    @warpThickness, @weftThickness,
    @weaveMode, @savedAt
);

sqlMap.select:
SELECT Idx, Name, Code, RepeatX, RepeatY, SavedAt
FROM WeavePattern
ORDER BY Idx ASC;

sqlMap.insert:
INSERT INTO WeavePattern (
    Name, Code, RepeatX, RepeatY,
    Cells, WarpColors, WeftColors,
    WarpThickness, WeftThickness,
    WeaveMode, SavedAt
) VALUES (
    @name, @code, @repeatX, @repeatY,
    @cells, @warpColors, @weftColors,
    @warpThickness, @weftThickness,
    @weaveMode, @savedAt
);

INSERT INTO WeavePattern (
    Name, Code, RepeatX, RepeatY,
    Cells, WarpColors, WeftColors,
    WarpThickness, WeftThickness,
    WeaveMode, SavedAt
) VALUES (
    @name, @code, @repeatX, @repeatY,
    @cells, @warpColors, @weftColors,
    @warpThickness, @weftThickness,
    @weaveMode, @savedAt
)
ON CONFLICT(Code) DO UPDATE SET
    Name          = @name,
    RepeatX       = @repeatX,
    RepeatY       = @repeatY,
    Cells         = @cells,
    WarpColors    = @warpColors,
    WeftColors    = @weftColors,
    WarpThickness = @warpThickness,
    WeftThickness = @weftThickness,
    WeaveMode     = @weaveMode,
    SavedAt       = @savedAt;
